function load$Grid(g) {
  g._$k = [];
  g._authorizeType = 2;
  g._$i = g._getColumnOrder('stt_rec');
  g._$d = g._getColumnOrder('ngay_ct');
  g._$t = g._getColumnOrder('&Tag;');
  g.add_onResponseComplete(on$GridAuthorize$ResponseComplete);
  g.add_commandEvent(on$GridAuthorize$ExecuteCommand);
}
/* <flatten type="Javascript"> */
function scatter$Grid(g) {fill$Grid(g, true);}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$GridAuthorize$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridAuthorize$ResponseComplete);} catch (ex) {}
  g._$k = g._authorizeType = g._$i = g._$d = g._$t = null;
}
function on$GridAuthorize$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Approve':
    case 'Cancel':
      if (g._authorizeType == 2) request$Authorize(g, action);
      break;
    case 'Undo':
      if (g._authorizeType == 1) request$Authorize(g, action);
      break;
    default:
      break;
  }
}
function request$Authorize(g, c) {
  if (g._rowCount == 0) return;
  var r = (g._activeCell ? g._activeRow : 1), s = g._$k.join(','), o = g._getItemValue(r, g._$t);
  o.row = r;
  if (isCheck$Grid(g)) g.request(o, c, c, [['s', 'Infinite', s]]);
}
function on$GridAuthorize$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Approve':
    case 'Cancel':
    case 'Undo':
      if (g._$k.length > 0) {
        g._$k = [];
        $find(g.get_id()).goToPage(-1);
      }
      break;
    default:
      break;
  }
}
/* </flatten> */
      &ScriptTag;
